  1→import { randomUUID } from 'node:crypto';
  2→
  3→import { Injectable, Logger, NotFoundException } from '@nestjs/common';
  4→
  5→import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
  6→import { OpenAIService } from '@modules/rest/open-ai/open-ai.service';
  7→import { CacheService } from '@modules/cache/cache.service';
  8→import { EnvConfigService } from '@modules/env-config/env-config.service';
  9→
 10→import { LogExecution } from '@decorators/log-execution.decorator';
 11→
 12→import { NEURAL_SEARCH_CONVERSATION_TTL } from '@constants/env-variables.constant';
 13→
 14→import { Namespaces } from '@interfaces/cache.interface';
 15→
 16→import { NeuralSearchQueryDto } from '@dto/neural-search/neural-search-query.dto';
 17→import { NeuralSearchResponseDto } from '@dto/neural-search/neural-search-response.dto';
 18→import { StartConversationDto, ContinueConversationDto } from '@dto/neural-search/neural-search-conversation.dto';
 19→import { ConversationResponseDto } from '@dto/neural-search/neural-search-conversation-response.dto';
 20→
 21→import {
 22→	IConversationState,
 23→	IConversationTurn,
 24→} from '@modules/rest/open-ai/interfaces/conversation-analysis.interface';
 25→
 26→@Injectable()
 27→export class NeuralSearchService {
 28→	private readonly logger = new Logger(NeuralSearchService.name);
 29→
 30→	constructor(
 31→		private readonly opensearchNeuralService: OpensearchNeuralService,
 32→		private readonly openAIService: OpenAIService,
 33→		private readonly cacheService: CacheService,
 34→		private readonly envConfigService: EnvConfigService,
 35→	) {}
 36→
 37→	@LogExecution({
 38→		paramFormatter: (params: [{ query: NeuralSearchQueryDto }]) => ({
 39→			q: params[0].query.q,
 40→			tags: params[0].query.tags,
 41→			limit: params[0].query.limit,
 42→		}),
 43→		responseFormatter: (response: NeuralSearchResponseDto) => ({
 44→			total: response.total,
 45→		}),
 46→	})
 47→	async search({
 48→		query,
 49→	}: {
 50→		query: NeuralSearchQueryDto;
 51→	}): Promise<NeuralSearchResponseDto> {
 52→		const products = await this.opensearchNeuralService.searchProducts({
 53→			queryText: query.q,
 54→			...(query.limit !== undefined && { size: query.limit }),
 55→			...(query.tags?.length && { tags: query.tags }),
 56→		});
 57→
 58→		return {
 59→			query: query.q,
 60→			total: products.length,
 61→			products,
 62→		};
 63→	}
 64→
 65→	@LogExecution({
 66→		paramFormatter: (params: [{ dto: StartConversationDto }]) => ({
 67→			q: params[0].dto.q,
 68→			limit: params[0].dto.limit,
 69→		}),
 70→	})
 71→	async startConversation({
 72→		dto,
 73→	}: {
 74→		dto: StartConversationDto;
 75→	}): Promise<ConversationResponseDto> {
 76→		const conversationId = randomUUID();
 77→
 78→		try {
 79→			const llmResult = await this.openAIService.analyzeSearchQuery({ query: dto.q });
 80→
 81→			if (llmResult.needsClarification && llmResult.questions?.length) {
 82→				const state: IConversationState = {
 83→					conversationId,
 84→					originalQuery: dto.q,
 85→					limit: dto.limit ?? 20,
 86→					turns: [],
 87→					llmAnalysis: llmResult,
 88→					createdAt: Date.now(),
 89→				};
 90→
 91→				await this.saveConversationState({ state });
 92→
 93→				return {
 94→					conversationId,
 95→					needsClarification: true,
 96→					questions: llmResult.questions,
 97→					analysis: llmResult.analysis,
 98→				};
 99→			}
100→
101→			const searchResults = await this.search({
102→				query: {
103→					q: llmResult.analysis.enhancedQuery,
104→					limit: dto.limit,
105→				},
106→			});
107→
108→			return {
109→				conversationId,
110→				needsClarification: false,
111→				analysis: llmResult.analysis,
112→				searchResults,
113→			};
114→		} catch (error) {
115→			this.logger.warn('LLM analysis failed, falling back to direct search', {
116→				error: error instanceof Error ? error.message : 'Unknown error',
117→			});
118→
119→			const searchResults = await this.search({
120→				query: { q: dto.q, limit: dto.limit },
121→			});
122→
123→			return {
124→				conversationId,
125→				needsClarification: false,
126→				searchResults,
127→			};
128→		}
129→	}
130→
131→	@LogExecution({
132→		paramFormatter: (params: [{ conversationId: string; dto: ContinueConversationDto }]) => ({
133→			conversationId: params[0].conversationId,
134→			answersCount: params[0].dto.answers.length,
135→		}),
136→	})
137→	async continueConversation({
138→		conversationId,
139→		dto,
140→	}: {
141→		conversationId: string;
142→		dto: ContinueConversationDto;
143→	}): Promise<ConversationResponseDto> {
144→		const state = await this.getConversationState({ conversationId });
145→
146→		if (!state) {
147→			throw new NotFoundException(`Conversation ${conversationId} not found or expired`);
148→		}
149→
150→		const newTurns: IConversationTurn[] = dto.answers.map((a) => ({
151→			question: a.question,
152→			answer: a.answer,
153→		}));
154→
155→		const allTurns = [...state.turns, ...newTurns];
156→		const limit = dto.limit ?? state.limit;
157→
158→		try {
159→			const llmResult = await this.openAIService.analyzeSearchQueryWithContext({
160→				originalQuery: state.originalQuery,
161→				turns: allTurns,
162→			});
163→
164→			if (llmResult.needsClarification && llmResult.questions?.length) {
165→				const updatedState: IConversationState = {
166→					...state,
167→					turns: allTurns,
168→					llmAnalysis: llmResult,
169→				};
170→
171→				await this.saveConversationState({ state: updatedState });
172→
173→				return {
174→					conversationId,
175→					needsClarification: true,
176→					questions: llmResult.questions,
177→					analysis: llmResult.analysis,
178→				};
179→			}
180→
181→			const searchResults = await this.search({
182→				query: {
183→					q: llmResult.analysis.enhancedQuery,
184→					limit,
185→				},
186→			});
187→
188→			await this.deleteConversationState({ conversationId });
189→
190→			return {
191→				conversationId,
192→				needsClarification: false,
193→				analysis: llmResult.analysis,
194→				searchResults,
195→			};
196→		} catch (error) {
197→			this.logger.warn('LLM analysis failed on continue, falling back to direct search', {
198→				error: error instanceof Error ? error.message : 'Unknown error',
199→			});
200→
201→			const searchResults = await this.search({
202→				query: { q: state.originalQuery, limit },
203→			});
204→
205→			return {
206→				conversationId,
207→				needsClarification: false,
208→				searchResults,
209→			};
210→		}
211→	}
212→
213→	private async saveConversationState({ state }: { state: IConversationState }): Promise<void> {
214→		const ttl = this.envConfigService.get<number>({
215→			key: NEURAL_SEARCH_CONVERSATION_TTL,
216→			converter: Number,
217→		});
218→
219→		await this.cacheService.set({
220→			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
221→			key: state.conversationId,
222→			value: state,
223→			ttl,
224→		});
225→	}
226→
227→	private async getConversationState({
228→		conversationId,
229→	}: {
230→		conversationId: string;
231→	}): Promise<IConversationState | null> {
232→		return this.cacheService.get<IConversationState>({
233→			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
234→			key: conversationId,
235→		});
236→	}
237→
238→	private async deleteConversationState({
239→		conversationId,
240→	}: {
241→		conversationId: string;
242→	}): Promise<void> {
243→		await this.cacheService.deleteOne({
244→			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
245→			key: conversationId,
246→		});
247→	}
