249→	renderSearchPageHtml({
250→		result,
251→		tags,
252→	}: {
253→		result: NeuralSearchResponseDto | null;
254→		tags: string[];
255→	}): string {
256→		const queryValue = result?.query ?? '';
257→		const tagsValue = tags.join(', ');
258→
259→		const productCards = result
260→			? result.products
261→					.map(
262→						(p) => `
263→			<div style="border:1px solid #ddd;border-radius:8px;padding:12px;width:220px;text-align:center;background:#fff;display:flex;flex-direction:column;align-items:center;">
264→				<img src="${p.style_card_image_url ?? ''}" alt="${p.name}" style="width:200px;height:200px;object-fit:contain;border-radius:4px;" onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><rect fill=%22%23eee%22 width=%22200%22 height=%22200%22/><text x=%2250%%22 y=%2250%%22 dominant-baseline=%22middle%22 text-anchor=%22middle%22 fill=%22%23999%22 font-size=%2214%22>No Image</text></svg>'"/>
265→				<div style="margin-top:8px;font-weight:600;font-size:14px;min-height:40px;">${p.name}</div>
266→				<div style="margin-top:4px;font-size:11px;color:#2563eb;font-weight:500;">Confidence: ${String(p.confidenceScore ?? 0)}%</div>
267→				<div style="color:#555;font-size:12px;margin-top:4px;">${p.primary_category_name ?? ''}</div>
268→				<div style="color:#666;font-size:11px;margin-top:2px;">${p.product_type ?? ''}</div>
269→				<div style="color:#777;font-size:11px;margin-top:2px;">${p.manufacturer ?? ''}</div>
270→				<div style="color:#888;font-size:11px;margin-top:2px;">${p.brand?.join(', ') ?? ''}</div>
271→			</div>`,
272→					)
273→					.join('')
274→			: '';
275→
276→		const resultsSection = result
277→			? `<p style="margin:16px 0 8px;">Query: <strong>${result.query}</strong>${tags.length ? ` | Tags: <strong>${tags.join(', ')}</strong>` : ''} | Results: ${result.total}</p>
278→			<div style="display:flex;flex-wrap:wrap;gap:16px;">${productCards}</div>`
279→			: '';
280→
281→		return `<!DOCTYPE html>
282→<html><head><meta charset="utf-8"><title>Neural Search</title></head>
283→<body style="font-family:system-ui,sans-serif;margin:20px;background:#f5f5f5;">
284→	<h2>Neural Search</h2>
285→	<form id="searchForm" style="margin-bottom:16px;">
286→		<div style="display:flex;gap:8px;margin-bottom:8px;">
287→			<input id="searchInput" name="q" type="text" value="${queryValue}" placeholder="Describe what you're looking for..."
288→				style="flex:1;max-width:500px;padding:10px 14px;font-size:15px;border:1px solid #ccc;border-radius:6px;outline:none;" />
289→			<button type="submit"
290→				style="padding:10px 20px;font-size:15px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">
291→				Ask AI
292→			</button>
293→		</div>
294→		<div style="display:flex;gap:8px;align-items:center;">
295→			<input id="tagsInput" type="text" value="${tagsValue}" placeholder="Category tags (comma-separated, e.g. T-Shirts, Apparel)"
296→				style="flex:1;max-width:500px;padding:8px 12px;font-size:13px;border:1px solid #ccc;border-radius:6px;outline:none;" />
297→		</div>
298→	</form>
299→	<div id="results">${resultsSection}</div>
300→	<script>
301→		document.getElementById('searchForm').addEventListener('submit', function(e) {
302→			e.preventDefault();
303→			var q = document.getElementById('searchInput').value.trim();
304→			if (!q) return;
305→			var url = '/api/v1/neural-search/view?q=' + encodeURIComponent(q);
306→			var tagsRaw = document.getElementById('tagsInput').value.trim();
307→			if (tagsRaw) {
308→				var tags = tagsRaw.split(',').map(function(t) { return t.trim(); }).filter(Boolean);
309→				tags.forEach(function(tag) { url += '&tags=' + encodeURIComponent(tag); });
310→			}
311→			window.location.href = url;
312→		});
313→	</script>
314→</body></html>`;
315→	}
316→}
