  1→import { Injectable, Logger } from '@nestjs/common';
  2→import { OpenAI } from 'openai';
  3→
  4→import { getEnv } from '@utils/get-env-variable.util';
  5→
  6→import { OPENAI_API_KEY } from '@constants/env-variables.constant';
  7→import { NEURAL_SEARCH_KNOWN_BRANDS } from '@constants/neural-search-brands.constant';
  8→
  9→import { MMSStyleToProcess } from '@interfaces/mms-style-to-process.interface';
 10→
 11→import { LogExecution } from '@decorators/log-execution.decorator';
 12→
 13→import {
 14→	ILlmAnalysisResult,
 15→	IConversationTurn,
 16→} from '@modules/rest/open-ai/interfaces/conversation-analysis.interface';
 17→
 18→export interface ProductFeatureResponse {
 19→	description?: string[];
 20→	error?: string;
 21→}
 22→
 23→export interface EmbeddingTextResponse {
 24→	text: string;
 25→}
 26→
 27→export interface ProductEmbeddingInput {
 28→	name: string;
 29→	product_type: string | null;
 30→	style_type: string | null;
 31→	primary_category_name: string | null;
 32→	sub_category_names: string[] | null;
 33→	broad_category_names: string[] | null;
 34→	features: string | null;
 35→	general_comments: string | null;
 36→	decoration_method: string | null;
 37→	manufacturer: string | null;
 38→	brand: string[] | null;
 39→	condensed_features: string[] | null;
 40→	sizes: string[] | null;
 41→}
 42→
 43→@Injectable()
 44→export class OpenAIService {
 45→	private readonly logger = new Logger(OpenAIService.name);
 46→	private readonly openai: OpenAI;
 47→
 48→	constructor() {
 49→		const apiKey = getEnv<string>({ key: OPENAI_API_KEY });
 50→		this.openai = new OpenAI({ apiKey, baseURL: 'https://api.openai.com/v1' });
 51→	}
 52→
 53→	async generateProductFeatures({
 54→		productInfo,
 55→	}: {
 56→		productInfo: MMSStyleToProcess;
 57→	}): Promise<ProductFeatureResponse> {
 58→		try {
 59→			this.logger.log(`Processing product features for id: ${productInfo.id}`);
 60→
 61→			const prompt = this.buildPrompt({ productInfo });
 62→
 63→			const response = await this.getOpenAIResponse(prompt);
 64→
 65→			this.logger.log(`Successfully generated features for id: ${productInfo.id}`);
 66→			return response;
 67→		} catch (error) {
 68→			this.logger.error(`Error processing product ${productInfo.id}:`, error);
 69→			return {
 70→				error: `Failed to process product: ${error instanceof Error ? error.message : 'Unknown error'}`,
 71→			};
 72→		}
 73→	}
 74→
 75→	@LogExecution({
 76→		paramFormatter: (params: [{ product: ProductEmbeddingInput }]) => ({
 77→			name: params[0].product.name,
 78→		}),
 79→	})
 80→	async generateEmbeddingText({
 81→		product,
 82→	}: {
 83→		product: ProductEmbeddingInput;
 84→	}): Promise<EmbeddingTextResponse> {
 85→		const productData = {
 86→			name: product.name,
 87→			product_type: product.product_type,
 88→			style_type: product.style_type,
 89→			category: product.primary_category_name,
 90→			subcategories: product.sub_category_names,
 91→			broad_categories: product.broad_category_names,
 92→			features: product.features,
 93→			description: product.general_comments,
 94→			decoration_method: product.decoration_method,
 95→			manufacturer: product.manufacturer,
 96→			brand: product.brand,
 97→			condensed_features: product.condensed_features,
 98→			sizes: product.sizes,
 99→		};
100→
101→		const completion = await this.openai.chat.completions.create({
102→			messages: [
103→				{
104→					role: 'system',
105→					content: `You are a senior data engineer and data analyst who is an expert in generating text embeddings for neural product search.
106→						Your task: given product data, produce a single natural-language paragraph optimized for a distilroberta-v1 embedding model (512 token limit).
107→
108→						Rules:
109→						- Write fluent, human-readable sentences — no bullet points, no pipe delimiters, no markdown.
110→						- Lead with the product name and what it is.
111→						- Describe key physical features, materials, and use cases.
112→						- Mention important category information (primary category, and few broad categories if they exist). as words, not as sentences.
113→						- Highlight occasions, events, and audiences this product is ideal for.
114→						- Include the decoration/customization method naturally (3-4 words).
115→						- Mention the manufacturer/brand only once if relevant.
116→						- Highlight occasions, events, and audiences this product is ideal for.
117→						- Count a few (6 max) key features and details from condensed_features if available, use 3-4 words per feature, and integrate them naturally into the text.
118→						- Skip null/empty fields silently — never say "unknown" or "N/A".
119→						- Do NOT invent features not present in the input data.
120→						- Output ONLY valid JSON: {"text": "your paragraph here"}`,
121→				},
122→				{
123→					role: 'user',
124→					content: `Generate embedding text for this product:\n${JSON.stringify(productData)}`,
125→				},
126→			],
127→			model: 'gpt-4o-mini',
128→			response_format: { type: 'json_object' },
129→			temperature: 0.3,
130→			max_tokens: 350,
131→		});
132→
133→		if (!completion.choices[0]?.message.content) {
134→			throw new Error('Empty response from OpenAI');
135→		}
136→
137→		const parsed = JSON.parse(
138→			completion.choices[0].message.content,
139→		) as EmbeddingTextResponse;
140→
141→		if (!parsed.text || typeof parsed.text !== 'string') {
142→			this.logger.error(
143→				'Invalid response format from OpenAI:',
144→				JSON.stringify(completion.choices[0].message.content),
145→			);
146→			return { text: '' };
147→		}
148→
149→		return parsed;
150→	}
151→
152→	@LogExecution({
153→		paramFormatter: (params: [{ query: string }]) => ({
154→			query: params[0].query,
155→		}),
156→	})
157→	async analyzeSearchQuery({ query }: { query: string }): Promise<ILlmAnalysisResult> {
158→		const completion = await this.openai.chat.completions.create({
159→			messages: [
160→				{ role: 'system', content: this.buildConversationSystemPrompt() },
161→				{ role: 'user', content: query },
162→			],
163→			model: 'gpt-4o-mini',
164→			response_format: { type: 'json_object' },
165→			temperature: 0.3,
166→			max_tokens: 800,
167→		});
168→
169→		return this.parseAnalysisResponse({ content: completion.choices[0]?.message.content });
170→	}
171→
172→	@LogExecution({
173→		paramFormatter: (params: [{ originalQuery: string; turns: IConversationTurn[] }]) => ({
174→			originalQuery: params[0].originalQuery,
175→			turnsCount: params[0].turns.length,
176→		}),
177→	})
178→	async analyzeSearchQueryWithContext({
179→		originalQuery,
180→		turns,
181→	}: {
182→		originalQuery: string;
183→		turns: IConversationTurn[];
184→	}): Promise<ILlmAnalysisResult> {
185→		const messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[] = [
186→			{ role: 'system', content: this.buildConversationSystemPrompt() },
187→			{ role: 'user', content: originalQuery },
188→		];
189→
190→		for (const turn of turns) {
191→			messages.push({
192→				role: 'assistant',
193→				content: JSON.stringify({
194→					needsClarification: true,
195→					questions: [turn.question],
196→					analysis: null,
197→				}),
198→			});
199→			messages.push({ role: 'user', content: turn.answer });
200→		}
201→
202→		messages.push({
203→			role: 'user',
204→			content: 'Based on all the information provided, now produce the final analysis JSON with needsClarification: false and a complete analysis object.',
205→		});
206→
207→		const completion = await this.openai.chat.completions.create({
208→			messages,
209→			model: 'gpt-4o-mini',
210→			response_format: { type: 'json_object' },
211→			temperature: 0.3,
212→			max_tokens: 800,
213→		});
214→
215→		return this.parseAnalysisResponse({ content: completion.choices[0]?.message.content });
216→	}
217→
218→	private parseAnalysisResponse({ content }: { content: string | null | undefined }): ILlmAnalysisResult {
219→		if (!content) {
220→			throw new Error('Empty response from OpenAI conversation analysis');
221→		}
222→
223→		const cleaned = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
224→		const parsed = JSON.parse(cleaned) as ILlmAnalysisResult;
225→
226→		if (typeof parsed.needsClarification !== 'boolean') {
227→			throw new Error('Invalid LLM analysis: missing needsClarification');
228→		}
229→
230→		if (!parsed.analysis && !parsed.needsClarification) {
231→			throw new Error('Invalid LLM analysis: missing analysis when no clarification needed');
232→		}
233→
234→		return parsed;
235→	}
236→
237→	private buildConversationSystemPrompt(): string {
238→		const brandsSample = NEURAL_SEARCH_KNOWN_BRANDS.slice(0, 50).join(', ');
239→
240→		return `You are a product search query analyzer for a custom apparel and promotional products store.
241→
242→Your task: analyze the customer's search query and extract structured signals to improve search results.
243→
244→Analyze for:
245→- intent: what the customer wants (e.g. "buy", "browse", "compare", "gift")
246→- gender: "men", "women", "unisex", or null if unclear
247→- useCase: occasion or purpose (e.g. "corporate event", "wedding", "team sports", "casual wear")
248→- style: aesthetic preference (e.g. "professional", "sporty", "casual", "vintage")
249→- budget: price sensitivity (e.g. "economy", "mid-range", "premium") or null
250→- keywords: important search terms extracted from query
251→- enhancedQuery: a refined, search-optimized version of the original query — short and sharp, focusing on product attributes
252→- productTypes: specific product categories (e.g. "T-Shirts", "Polo Shirts", "Hoodies", "Caps")
253→- brands: recognized brand names from query
254→- priceLevels: ["cheap", "mid-range", "premium"] based on signals
255→
256→Known brands (partial list): ${brandsSample}
257→
258→Rules:
259→1. If the query is clear and specific enough to search, set needsClarification: false
260→2. If the query is too vague or ambiguous (e.g. "I need something nice"), set needsClarification: true and provide 1-3 short, targeted questions
261→3. ALWAYS provide best-effort analysis even when asking questions
262→4. enhancedQuery must be concise and search-optimized — strip filler words, focus on product attributes
263→5. Output ONLY valid JSON
264→
265→Output format:
266→{
267→  "needsClarification": boolean,
268→  "questions": ["question1", "question2"],
269→  "analysis": {
270→    "intent": "string",
271→    "gender": "string | null",
272→    "useCase": "string | null",
273→    "style": "string | null",
274→    "budget": "string | null",
275→    "keywords": ["string"],
276→    "enhancedQuery": "string",
277→    "productTypes": ["string"],
278→    "brands": ["string"],
279→    "priceLevels": ["string"]
280→  }
281→}`;
282→	}
283→
284→	private buildPrompt({ productInfo }: { productInfo: MMSStyleToProcess }): string {
285→		return `
286→The description should be present and be suitable for product recommendation model without mentioning names and brands.
287→Description should be an array of feature strings.
288→Response format: { "description": feature[] } in JSON format.
289→
290→Product in JSON format: ${JSON.stringify(productInfo, null, 2)}
291→`;
292→	}
293→
294→	private async getOpenAIResponse(prompt: string): Promise<ProductFeatureResponse> {
295→		const completion = await this.openai.chat.completions.create({
296→			messages: [
297→				{
298→					role: 'system',
299→					content: `You are an expert in data preprocessing and feature engineering for machine learning.
300→				Your job is prepare data for training Related Products model based on "Content-based" approach.
301→				Your need to define key features, product details and important words for products and build array of features.
302→          `,
303→				},
304→				{ role: 'user', content: [{ type: 'text', text: prompt }] },
305→			],
306→			model: 'gpt-4o-mini',
307→			response_format: { type: 'json_object' },
308→		});
309→
310→		if (!completion.choices[0]) {
311→			return { error: 'No response from OpenAI' };
312→		}
313→
314→		const content = completion.choices[0].message.content;
315→		if (!content) {
316→			return { error: 'Empty response from OpenAI' };
317→		}
318→
319→		try {
320→			const parsedResponse = JSON.parse(content) as ProductFeatureResponse;
321→
322→			const fieldNames = Object.keys(parsedResponse);
323→			const firstFieldName = fieldNames[0] as keyof ProductFeatureResponse;
324→
325→			if (!parsedResponse.description) {
326→				const fieldValue = parsedResponse[firstFieldName];
327→				return {
328→					description:
329→						typeof fieldValue === 'string'
330→							? (JSON.parse(fieldValue) as string[])
331→							: (fieldValue ?? []),
332→					...parsedResponse,
333→				};
334→			}
335→
336→			return parsedResponse;
337→		} catch (parseError) {
338→			this.logger.error('Failed to parse OpenAI response:', parseError);
339→			return { error: 'Failed to parse OpenAI response' };
340→		}
341→	}
342→}
