import { randomUUID } from 'node:crypto';

import { Injectable, Logger, NotFoundException } from '@nestjs/common';

import { CacheService } from '@modules/cache/cache.service';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
import { OpenAIService } from '@modules/rest/open-ai/open-ai.service';
import {
	IConversationState,
	IConversationTurn,
} from '@modules/rest/open-ai/interfaces/conversation-analysis.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

import { NEURAL_SEARCH_CONVERSATION_TTL } from '@constants/env-variables.constant';

import { Namespaces } from '@interfaces/cache.interface';

import {
	StartConversationDto,
	ContinueConversationDto,
} from '@dto/neural-search/neural-search-conversation.dto';
import { ConversationResponseDto } from '@dto/neural-search/neural-search-conversation-response.dto';
import { NeuralSearchQueryDto } from '@dto/neural-search/neural-search-query.dto';
import { NeuralSearchResponseDto } from '@dto/neural-search/neural-search-response.dto';

@Injectable()
export class NeuralSearchService {
	private readonly logger = new Logger(NeuralSearchService.name);

	constructor(
		private readonly opensearchNeuralService: OpensearchNeuralService,
		private readonly openAIService: OpenAIService,
		private readonly cacheService: CacheService,
		private readonly envConfigService: EnvConfigService,
	) {}

	@LogExecution({
		paramFormatter: (params: [{ query: NeuralSearchQueryDto }]) => ({
			q: params[0].query.q,
			tags: params[0].query.tags,
			limit: params[0].query.limit,
		}),
		responseFormatter: (response: NeuralSearchResponseDto) => ({
			total: response.total,
		}),
	})
	async search({
		query,
	}: {
		query: NeuralSearchQueryDto;
	}): Promise<NeuralSearchResponseDto> {
		const products = await this.opensearchNeuralService.searchProducts({
			queryText: query.q,
			...(query.limit !== undefined && { size: query.limit }),
			...(query.tags?.length && { tags: query.tags }),
		});

		return {
			query: query.q,
			total: products.length,
			products,
		};
	}

	@LogExecution({
		paramFormatter: (params: [{ dto: StartConversationDto }]) => ({
			q: params[0].dto.q,
			limit: params[0].dto.limit,
		}),
	})
	async startConversation({
		dto,
	}: {
		dto: StartConversationDto;
	}): Promise<ConversationResponseDto> {
		const conversationId = randomUUID();

		try {
			const llmResult = await this.openAIService.analyzeSearchQuery({ query: dto.q });

			if (llmResult.needsClarification && llmResult.questions?.length) {
				const state: IConversationState = {
					conversationId,
					originalQuery: dto.q,
					limit: dto.limit ?? 20,
					turns: [],
					llmAnalysis: llmResult,
					createdAt: Date.now(),
				};

				await this.saveConversationState({ state });

				return {
					conversationId,
					needsClarification: true,
					questions: llmResult.questions,
					analysis: llmResult.analysis,
				};
			}

			const searchResults = await this.search({
				query: {
					q: llmResult.analysis.enhancedQuery,
					...(dto.limit !== undefined && { limit: dto.limit }),
				},
			});

			return {
				conversationId,
				needsClarification: false,
				analysis: llmResult.analysis,
				searchResults,
			};
		} catch (error) {
			this.logger.warn('LLM analysis failed, falling back to direct search', {
				error: error instanceof Error ? error.message : 'Unknown error',
			});

			const searchResults = await this.search({
				query: {
					q: dto.q,
					...(dto.limit !== undefined && { limit: dto.limit }),
				},
			});

			return {
				conversationId,
				needsClarification: false,
				searchResults,
			};
		}
	}

	@LogExecution({
		paramFormatter: (
			params: [{ conversationId: string; dto: ContinueConversationDto }],
		) => ({
			conversationId: params[0].conversationId,
			answersCount: params[0].dto.answers.length,
		}),
	})
	async continueConversation({
		conversationId,
		dto,
	}: {
		conversationId: string;
		dto: ContinueConversationDto;
	}): Promise<ConversationResponseDto> {
		const state = await this.getConversationState({ conversationId });

		if (!state) {
			throw new NotFoundException(`Conversation ${conversationId} not found or expired`);
		}

		const newTurns: IConversationTurn[] = dto.answers.map((a) => ({
			question: a.question,
			answer: a.answer,
		}));

		const allTurns = [...state.turns, ...newTurns];
		const limit = dto.limit ?? state.limit;

		try {
			const llmResult = await this.openAIService.analyzeSearchQueryWithContext({
				originalQuery: state.originalQuery,
				turns: allTurns,
			});

			if (llmResult.needsClarification && llmResult.questions?.length) {
				const updatedState: IConversationState = {
					...state,
					turns: allTurns,
					llmAnalysis: llmResult,
				};

				await this.saveConversationState({ state: updatedState });

				return {
					conversationId,
					needsClarification: true,
					questions: llmResult.questions,
					analysis: llmResult.analysis,
				};
			}

			const searchResults = await this.search({
				query: {
					q: llmResult.analysis.enhancedQuery,
					limit,
				},
			});

			await this.deleteConversationState({ conversationId });

			return {
				conversationId,
				needsClarification: false,
				analysis: llmResult.analysis,
				searchResults,
			};
		} catch (error) {
			this.logger.warn('LLM analysis failed on continue, falling back to direct search', {
				error: error instanceof Error ? error.message : 'Unknown error',
			});

			const searchResults = await this.search({
				query: { q: state.originalQuery, limit },
			});

			return {
				conversationId,
				needsClarification: false,
				searchResults,
			};
		}
	}

	private async saveConversationState({
		state,
	}: {
		state: IConversationState;
	}): Promise<void> {
		const ttl = this.envConfigService.get<number>({
			key: NEURAL_SEARCH_CONVERSATION_TTL,
			converter: Number,
		});

		await this.cacheService.set({
			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
			key: state.conversationId,
			value: state,
			ttl,
		});
	}

	private async getConversationState({
		conversationId,
	}: {
		conversationId: string;
	}): Promise<IConversationState | null> {
		return this.cacheService.get<IConversationState>({
			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
			key: conversationId,
		});
	}

	private async deleteConversationState({
		conversationId,
	}: {
		conversationId: string;
	}): Promise<void> {
		await this.cacheService.deleteOne({
			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
			key: conversationId,
		});
	}

	renderSearchPageHtml({
		result,
		tags,
	}: {
		result: NeuralSearchResponseDto | null;
		tags: string[];
	}): string {
		const queryValue = result?.query ?? '';
		const tagsValue = tags.join(', ');

		const productCards = result
			? result.products
					.map(
						(p) => `
			<div style="border:1px solid #ddd;border-radius:8px;padding:12px;width:220px;text-align:center;background:#fff;display:flex;flex-direction:column;align-items:center;">
				<img src="${p.style_card_image_url ?? ''}" alt="${p.name}" style="width:200px;height:200px;object-fit:contain;border-radius:4px;" onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><rect fill=%22%23eee%22 width=%22200%22 height=%22200%22/><text x=%2250%%22 y=%2250%%22 dominant-baseline=%22middle%22 text-anchor=%22middle%22 fill=%22%23999%22 font-size=%2214%22>No Image</text></svg>'"/>
				<div style="margin-top:8px;font-weight:600;font-size:14px;min-height:40px;">${p.name}</div>
				<div style="margin-top:4px;font-size:11px;color:#2563eb;font-weight:500;">Confidence: ${String(p.confidenceScore ?? 0)}%</div>
				<div style="color:#555;font-size:12px;margin-top:4px;">${p.primary_category_name ?? ''}</div>
				<div style="color:#666;font-size:11px;margin-top:2px;">${p.product_type ?? ''}</div>
				<div style="color:#777;font-size:11px;margin-top:2px;">${p.manufacturer ?? ''}</div>
				<div style="color:#888;font-size:11px;margin-top:2px;">${p.brand?.join(', ') ?? ''}</div>
			</div>`,
					)
					.join('')
			: '';

		const resultsSection = result
			? `<p style="margin:16px 0 8px;">Query: <strong>${result.query}</strong>${tags.length ? ` | Tags: <strong>${tags.join(', ')}</strong>` : ''} | Results: ${result.total}</p>
			<div style="display:flex;flex-wrap:wrap;gap:16px;">${productCards}</div>`
			: '';

		return `<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>Neural Search</title></head>
<body style="font-family:system-ui,sans-serif;margin:20px;background:#f5f5f5;">
	<h2>Neural Search</h2>
	<form id="searchForm" style="margin-bottom:16px;">
		<div style="display:flex;gap:8px;margin-bottom:8px;">
			<input id="searchInput" name="q" type="text" value="${queryValue}" placeholder="Describe what you're looking for..."
				style="flex:1;max-width:500px;padding:10px 14px;font-size:15px;border:1px solid #ccc;border-radius:6px;outline:none;" />
			<button type="submit"
				style="padding:10px 20px;font-size:15px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">
				Ask AI
			</button>
		</div>
		<div style="display:flex;gap:8px;align-items:center;">
			<input id="tagsInput" type="text" value="${tagsValue}" placeholder="Category tags (comma-separated, e.g. T-Shirts, Apparel)"
				style="flex:1;max-width:500px;padding:8px 12px;font-size:13px;border:1px solid #ccc;border-radius:6px;outline:none;" />
		</div>
	</form>
	<div id="results">${resultsSection}</div>
	<script>
		document.getElementById('searchForm').addEventListener('submit', function(e) {
			e.preventDefault();
			var q = document.getElementById('searchInput').value.trim();
			if (!q) return;
			var url = '/api/v1/neural-search/view?q=' + encodeURIComponent(q);
			var tagsRaw = document.getElementById('tagsInput').value.trim();
			if (tagsRaw) {
				var tags = tagsRaw.split(',').map(function(t) { return t.trim(); }).filter(Boolean);
				tags.forEach(function(tag) { url += '&tags=' + encodeURIComponent(tag); });
			}
			window.location.href = url;
		});
	</script>
</body></html>`;
	}
}

