import { Injectable, Logger } from '@nestjs/common';
import { OpenAI } from 'openai';

import { getEnv } from '@utils/get-env-variable.util';

import { OPENAI_API_KEY } from '@constants/env-variables.constant';
import { NEURAL_SEARCH_KNOWN_BRANDS } from '@constants/neural-search-brands.constant';

import { MMSStyleToProcess } from '@interfaces/mms-style-to-process.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

import {
	ILlmAnalysisResult,
	IConversationTurn,
} from '@modules/rest/open-ai/interfaces/conversation-analysis.interface';

export interface ProductFeatureResponse {
	description?: string[];
	error?: string;
}

export interface EmbeddingTextResponse {
	text: string;
}

export interface ProductEmbeddingInput {
	name: string;
	product_type: string | null;
	style_type: string | null;
	primary_category_name: string | null;
	sub_category_names: string[] | null;
	broad_category_names: string[] | null;
	features: string | null;
	general_comments: string | null;
	decoration_method: string | null;
	manufacturer: string | null;
	brand: string[] | null;
	condensed_features: string[] | null;
	sizes: string[] | null;
}

@Injectable()
export class OpenAIService {
	private readonly logger = new Logger(OpenAIService.name);
	private readonly openai: OpenAI;

	constructor() {
		const apiKey = getEnv<string>({ key: OPENAI_API_KEY });
		this.openai = new OpenAI({ apiKey, baseURL: 'https://api.openai.com/v1' });
	}

	async generateProductFeatures({
		productInfo,
	}: {
		productInfo: MMSStyleToProcess;
	}): Promise<ProductFeatureResponse> {
		try {
			this.logger.log(`Processing product features for id: ${productInfo.id}`);

			const prompt = this.buildPrompt({ productInfo });

			const response = await this.getOpenAIResponse(prompt);

			this.logger.log(`Successfully generated features for id: ${productInfo.id}`);
			return response;
		} catch (error) {
			this.logger.error(`Error processing product ${productInfo.id}:`, error);
			return {
				error: `Failed to process product: ${error instanceof Error ? error.message : 'Unknown error'}`,
			};
		}
	}

	@LogExecution({
		paramFormatter: (params: [{ product: ProductEmbeddingInput }]) => ({
			name: params[0].product.name,
		}),
	})
	async generateEmbeddingText({
		product,
	}: {
		product: ProductEmbeddingInput;
	}): Promise<EmbeddingTextResponse> {
		const productData = {
			name: product.name,
			product_type: product.product_type,
			style_type: product.style_type,
			category: product.primary_category_name,
			subcategories: product.sub_category_names,
			broad_categories: product.broad_category_names,
			features: product.features,
			description: product.general_comments,
			decoration_method: product.decoration_method,
			manufacturer: product.manufacturer,
			brand: product.brand,
			condensed_features: product.condensed_features,
			sizes: product.sizes,
		};

		const completion = await this.openai.chat.completions.create({
			messages: [
				{
					role: 'system',
					content: `You are a senior data engineer and data analyst who is an expert in generating text embeddings for neural product search.
						Your task: given product data, produce a single natural-language paragraph optimized for a distilroberta-v1 embedding model (512 token limit).

						Rules:
						- Write fluent, human-readable sentences — no bullet points, no pipe delimiters, no markdown.
						- Lead with the product name and what it is.
						- Describe key physical features, materials, and use cases.
						- Mention important category information (primary category, and few broad categories if they exist). as words, not as sentences.
						- Highlight occasions, events, and audiences this product is ideal for.
						- Include the decoration/customization method naturally (3-4 words).
						- Mention the manufacturer/brand only once if relevant.
						- Highlight occasions, events, and audiences this product is ideal for.
						- Count a few (6 max) key features and details from condensed_features if available, use 3-4 words per feature, and integrate them naturally into the text.
						- Skip null/empty fields silently — never say "unknown" or "N/A".
						- Do NOT invent features not present in the input data.
						- Output ONLY valid JSON: {"text": "your paragraph here"}`,
				},
				{
					role: 'user',
					content: `Generate embedding text for this product:\n${JSON.stringify(productData)}`,
				},
			],
			model: 'gpt-4o-mini',
			response_format: { type: 'json_object' },
			temperature: 0.3,
			max_tokens: 350,
		});

		if (!completion.choices[0]?.message.content) {
			throw new Error('Empty response from OpenAI');
		}

		const parsed = JSON.parse(
			completion.choices[0].message.content,
		) as EmbeddingTextResponse;

		if (!parsed.text || typeof parsed.text !== 'string') {
			this.logger.error(
				'Invalid response format from OpenAI:',
				JSON.stringify(completion.choices[0].message.content),
			);
			return { text: '' };
		}

		return parsed;
	}

	@LogExecution({
		paramFormatter: (params: [{ query: string }]) => ({
			query: params[0].query,
		}),
	})
	async analyzeSearchQuery({ query }: { query: string }): Promise<ILlmAnalysisResult> {
		const completion = await this.openai.chat.completions.create({
			messages: [
				{ role: 'system', content: this.buildConversationSystemPrompt() },
				{ role: 'user', content: query },
			],
			model: 'gpt-4o-mini',
			response_format: { type: 'json_object' },
			temperature: 0.3,
			max_tokens: 800,
		});

		return this.parseAnalysisResponse({
			content: completion.choices[0]?.message.content,
		});
	}

	@LogExecution({
		paramFormatter: (
			params: [{ originalQuery: string; turns: IConversationTurn[] }],
		) => ({
			originalQuery: params[0].originalQuery,
			turnsCount: params[0].turns.length,
		}),
	})
	async analyzeSearchQueryWithContext({
		originalQuery,
		turns,
	}: {
		originalQuery: string;
		turns: IConversationTurn[];
	}): Promise<ILlmAnalysisResult> {
		const messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[] = [
			{ role: 'system', content: this.buildConversationSystemPrompt() },
			{ role: 'user', content: originalQuery },
		];

		for (const turn of turns) {
			messages.push({
				role: 'assistant',
				content: JSON.stringify({
					needsClarification: true,
					questions: [turn.question],
					analysis: null,
				}),
			});
			messages.push({ role: 'user', content: turn.answer });
		}

		messages.push({
			role: 'user',
			content:
				'Based on all the information provided, now produce the final analysis JSON with needsClarification: false and a complete analysis object.',
		});

		const completion = await this.openai.chat.completions.create({
			messages,
			model: 'gpt-4o-mini',
			response_format: { type: 'json_object' },
			temperature: 0.3,
			max_tokens: 800,
		});

		return this.parseAnalysisResponse({
			content: completion.choices[0]?.message.content,
		});
	}

	private parseAnalysisResponse({
		content,
	}: {
		content: string | null | undefined;
	}): ILlmAnalysisResult {
		if (!content) {
			throw new Error('Empty response from OpenAI conversation analysis');
		}

		const cleaned = content
			.replace(/```json\s*/g, '')
			.replace(/```\s*/g, '')
			.trim();
		const parsed = JSON.parse(cleaned) as ILlmAnalysisResult;

		if (typeof parsed.needsClarification !== 'boolean') {
			throw new Error('Invalid LLM analysis: missing needsClarification');
		}

		// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
		if (!parsed.analysis && !parsed.needsClarification) {
			throw new Error(
				'Invalid LLM analysis: missing analysis when no clarification needed',
			);
		}

		return parsed;
	}

	private buildConversationSystemPrompt(): string {
		const brandsSample = NEURAL_SEARCH_KNOWN_BRANDS.slice(0, 50).join(', ');

		return `You are a product search query analyzer for a custom apparel and promotional products store.

Your task: analyze the customer's search query and extract structured signals to improve search results.

Analyze for:
- intent: what the customer wants (e.g. "buy", "browse", "compare", "gift")
- gender: "men", "women", "unisex", or null if unclear
- useCase: occasion or purpose (e.g. "corporate event", "wedding", "team sports", "casual wear")
- style: aesthetic preference (e.g. "professional", "sporty", "casual", "vintage")
- budget: price sensitivity (e.g. "economy", "mid-range", "premium") or null
- keywords: important search terms extracted from query
- enhancedQuery: a refined, search-optimized version of the original query — short and sharp, focusing on product attributes
- productTypes: specific product categories (e.g. "T-Shirts", "Polo Shirts", "Hoodies", "Caps")
- brands: recognized brand names from query
- priceLevels: ["cheap", "mid-range", "premium"] based on signals

Known brands (partial list): ${brandsSample}

Rules:
1. If the query is clear and specific enough to search, set needsClarification: false
2. If the query is too vague or ambiguous (e.g. "I need something nice"), set needsClarification: true and provide 1-3 short, targeted questions
3. ALWAYS provide best-effort analysis even when asking questions
4. enhancedQuery must be concise and search-optimized — strip filler words, focus on product attributes
5. Output ONLY valid JSON

Output format:
{
  "needsClarification": boolean,
  "questions": ["question1", "question2"],
  "analysis": {
    "intent": "string",
    "gender": "string | null",
    "useCase": "string | null",
    "style": "string | null",
    "budget": "string | null",
    "keywords": ["string"],
    "enhancedQuery": "string",
    "productTypes": ["string"],
    "brands": ["string"],
    "priceLevels": ["string"]
  }
}`;
	}

	private buildPrompt({ productInfo }: { productInfo: MMSStyleToProcess }): string {
		return `
The description should be present and be suitable for product recommendation model without mentioning names and brands.
Description should be an array of feature strings.
Response format: { "description": feature[] } in JSON format.

Product in JSON format: ${JSON.stringify(productInfo, null, 2)}
`;
	}

	private async getOpenAIResponse(prompt: string): Promise<ProductFeatureResponse> {
		const completion = await this.openai.chat.completions.create({
			messages: [
				{
					role: 'system',
					content: `You are an expert in data preprocessing and feature engineering for machine learning.
				Your job is prepare data for training Related Products model based on "Content-based" approach.
				Your need to define key features, product details and important words for products and build array of features.
          `,
				},
				{ role: 'user', content: [{ type: 'text', text: prompt }] },
			],
			model: 'gpt-4o-mini',
			response_format: { type: 'json_object' },
		});

		if (!completion.choices[0]) {
			return { error: 'No response from OpenAI' };
		}

		const content = completion.choices[0].message.content;
		if (!content) {
			return { error: 'Empty response from OpenAI' };
		}

		try {
			const parsedResponse = JSON.parse(content) as ProductFeatureResponse;

			const fieldNames = Object.keys(parsedResponse);
			const firstFieldName = fieldNames[0] as keyof ProductFeatureResponse;

			if (!parsedResponse.description) {
				const fieldValue = parsedResponse[firstFieldName];
				return {
					description:
						typeof fieldValue === 'string'
							? (JSON.parse(fieldValue) as string[])
							: (fieldValue ?? []),
					...parsedResponse,
				};
			}

			return parsedResponse;
		} catch (parseError) {
			this.logger.error('Failed to parse OpenAI response:', parseError);
			return { error: 'Failed to parse OpenAI response' };
		}
	}
}

