import { Body, Controller, Get, Header, Param, ParseUUIDPipe, Post, Query } from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';

import { NeuralSearchService } from '@modules/rest/neural-search/neural-search.service';

import { LogExecution } from '@decorators/log-execution.decorator';

import { NeuralSearchQueryDto } from '@dto/neural-search/neural-search-query.dto';
import { NeuralSearchResponseDto } from '@dto/neural-search/neural-search-response.dto';
import {
	StartConversationDto,
	ContinueConversationDto,
} from '@dto/neural-search/neural-search-conversation.dto';
import { ConversationResponseDto } from '@dto/neural-search/neural-search-conversation-response.dto';

@ApiTags('Neural Search')
@Controller('neural-search')
export class NeuralSearchController {
	constructor(private readonly neuralSearchService: NeuralSearchService) {}

	@Get()
	@ApiOperation({
		summary: 'Search products using natural language via neural embeddings',
	})
	@ApiResponse({
		status: 200,
		description: 'Returns semantically relevant products',
		type: NeuralSearchResponseDto,
	})
	@ApiResponse({ status: 400, description: 'Invalid query parameters' })
	@LogExecution({
		paramFormatter: (params: [NeuralSearchQueryDto]) => ({
			q: params[0].q,
			tags: params[0].tags,
			limit: params[0].limit,
		}),
		responseFormatter: (response: NeuralSearchResponseDto) => ({
			total: response.total,
		}),
	})
	async search(@Query() query: NeuralSearchQueryDto): Promise<NeuralSearchResponseDto> {
		return this.neuralSearchService.search({ query });
	}

	@Post('conversation')
	@ApiOperation({
		summary:
			'Start a conversational search — LLM analyzes query and may ask clarifying questions',
	})
	@ApiResponse({
		status: 201,
		description: 'Returns conversation state with either questions or search results',
		type: ConversationResponseDto,
	})
	@ApiResponse({ status: 400, description: 'Invalid request body' })
	@LogExecution({
		paramFormatter: (params: [StartConversationDto]) => ({
			q: params[0].q,
			limit: params[0].limit,
		}),
	})
	async startConversation(
		@Body() dto: StartConversationDto,
	): Promise<ConversationResponseDto> {
		return this.neuralSearchService.startConversation({ dto });
	}

	@Post('conversation/:conversationId')
	@ApiOperation({
		summary: 'Continue a conversation — provide answers to clarification questions',
	})
	@ApiResponse({
		status: 201,
		description:
			'Returns updated conversation state with search results or more questions',
		type: ConversationResponseDto,
	})
	@ApiResponse({ status: 400, description: 'Invalid request body' })
	@ApiResponse({ status: 404, description: 'Conversation not found or expired' })
	@LogExecution({
		paramFormatter: (params: [string, ContinueConversationDto]) => ({
			conversationId: params[0],
			answersCount: params[1].answers.length,
		}),
	})
	async continueConversation(
		@Param('conversationId', ParseUUIDPipe) conversationId: string,
		@Body() dto: ContinueConversationDto,
	): Promise<ConversationResponseDto> {
		return this.neuralSearchService.continueConversation({ conversationId, dto });
	}

	@Get('view')
	@ApiOperation({ summary: 'Visual HTML view of neural search results' })
	@ApiResponse({ status: 200, description: 'Returns HTML page with product cards' })
	@Header('Content-Type', 'text/html')
	async view(
		@Query('q') q?: string,
		@Query('limit') limit?: string,
		@Query('tags') tags?: string | string[],
	): Promise<string> {
		if (!q) {
			return this.neuralSearchService.renderSearchPageHtml({ result: null, tags: [] });
		}

		const parsedTags = tags ? (Array.isArray(tags) ? tags : [tags]) : [];

		const query: NeuralSearchQueryDto = {
			q,
			...(limit !== undefined && { limit: Number(limit) }),
			...(parsedTags.length > 0 && { tags: parsedTags }),
		};
		const result = await this.neuralSearchService.search({ query });

		return this.neuralSearchService.renderSearchPageHtml({ result, tags: parsedTags });
	}
}

