 28→@Injectable()
 29→export class NeuralSearchService {
 30→	private readonly logger = new Logger(NeuralSearchService.name);
 31→
 32→	constructor(
 33→		private readonly opensearchNeuralService: OpensearchNeuralService,
 34→		private readonly openAIService: OpenAIService,
 35→		private readonly cacheService: CacheService,
 36→		private readonly envConfigService: EnvConfigService,
