 39→	@LogExecution({
 40→		paramFormatter: (params: [{ query: NeuralSearchQueryDto }]) => ({
 41→			q: params[0].query.q,
 42→			tags: params[0].query.tags,
 43→			limit: params[0].query.limit,
 44→		}),
 45→		responseFormatter: (response: NeuralSearchResponseDto) => ({
 46→			total: response.total,
 47→		}),
 48→	})
 49→	async search({
 50→		query,
 51→	}: {
 52→		query: NeuralSearchQueryDto;
 53→	}): Promise<NeuralSearchResponseDto> {
 54→		const products = await this.opensearchNeuralService.searchProducts({
 55→			queryText: query.q,
 56→			...(query.limit !== undefined && { size: query.limit }),
 57→			...(query.tags?.length && { tags: query.tags }),
 58→		});
 59→
 60→		return {
 61→			query: query.q,
 62→			total: products.length,
 63→			products,
 64→		};
 65→	}
 66→
 67→	@LogExecution({
 68→		paramFormatter: (params: [{ dto: StartConversationDto }]) => ({
 69→			q: params[0].dto.q,
 70→			limit: params[0].dto.limit,
 71→		}),
 72→	})
 73→	async startConversation({
 74→		dto,
 75→	}: {
 76→		dto: StartConversationDto;
 77→	}): Promise<ConversationResponseDto> {
 78→		const conversationId = randomUUID();
 79→
 80→		try {
 81→			const llmResult = await this.openAIService.analyzeSearchQuery({ query: dto.q });
 82→
 83→			if (llmResult.needsClarification && llmResult.questions?.length) {
 84→				const state: IConversationState = {
 85→					conversationId,
 86→					originalQuery: dto.q,
 87→					limit: dto.limit ?? 20,
 88→					turns: [],
 89→					llmAnalysis: llmResult,
 90→					createdAt: Date.now(),
 91→				};
 92→
 93→				await this.saveConversationState({ state });
 94→
 95→				return {
 96→					conversationId,
 97→					needsClarification: true,
 98→					questions: llmResult.questions,
 99→					analysis: llmResult.analysis,
100→				};
101→			}
102→
103→			const searchResults = await this.search({
104→				query: {
105→					q: llmResult.analysis.enhancedQuery,
106→					...(dto.limit !== undefined && { limit: dto.limit }),
107→				},
108→			});
109→
110→			return {
111→				conversationId,
112→				needsClarification: false,
113→				analysis: llmResult.analysis,
114→				searchResults,
115→			};
116→		} catch (error) {
117→			this.logger.warn('LLM analysis failed, falling back to direct search', {
118→				error: error instanceof Error ? error.message : 'Unknown error',
119→			});
120→
121→			const searchResults = await this.search({
122→				query: {
123→					q: dto.q,
124→					...(dto.limit !== undefined && { limit: dto.limit }),
125→				},
126→			});
127→
128→			return {
129→				conversationId,
130→				needsClarification: false,
131→				searchResults,
132→			};
133→		}
134→	}
135→
136→	@LogExecution({
137→		paramFormatter: (
138→			params: [{ conversationId: string; dto: ContinueConversationDto }],
139→		) => ({
140→			conversationId: params[0].conversationId,
141→			answersCount: params[0].dto.answers.length,
142→		}),
143→	})
144→	async continueConversation({
145→		conversationId,
146→		dto,
147→	}: {
148→		conversationId: string;
149→		dto: ContinueConversationDto;
150→	}): Promise<ConversationResponseDto> {
151→		const state = await this.getConversationState({ conversationId });
152→
153→		if (!state) {
154→			throw new NotFoundException(`Conversation ${conversationId} not found or expired`);
155→		}
156→
157→		const newTurns: IConversationTurn[] = dto.answers.map((a) => ({
158→			question: a.question,
159→			answer: a.answer,
160→		}));
161→
162→		const allTurns = [...state.turns, ...newTurns];
163→		const limit = dto.limit ?? state.limit;
164→
165→		try {
166→			const llmResult = await this.openAIService.analyzeSearchQueryWithContext({
167→				originalQuery: state.originalQuery,
168→				turns: allTurns,
169→			});
170→
171→			if (llmResult.needsClarification && llmResult.questions?.length) {
172→				const updatedState: IConversationState = {
173→					...state,
174→					turns: allTurns,
175→					llmAnalysis: llmResult,
176→				};
177→
178→				await this.saveConversationState({ state: updatedState });
179→
180→				return {
181→					conversationId,
182→					needsClarification: true,
183→					questions: llmResult.questions,
184→					analysis: llmResult.analysis,
185→				};
186→			}
187→
188→			const searchResults = await this.search({
189→				query: {
190→					q: llmResult.analysis.enhancedQuery,
191→					limit,
192→				},
193→			});
194→
195→			await this.deleteConversationState({ conversationId });
196→
197→			return {
198→				conversationId,
199→				needsClarification: false,
200→				analysis: llmResult.analysis,
201→				searchResults,
202→			};
203→		} catch (error) {
204→			this.logger.warn('LLM analysis failed on continue, falling back to direct search', {
205→				error: error instanceof Error ? error.message : 'Unknown error',
206→			});
207→
208→			const searchResults = await this.search({
209→				query: { q: state.originalQuery, limit },
210→			});
211→
212→			return {
213→				conversationId,
214→				needsClarification: false,
215→				searchResults,
216→			};
217→		}
218→	}
