220→	private async saveConversationState({
221→		state,
222→	}: {
223→		state: IConversationState;
224→	}): Promise<void> {
225→		const ttl = this.envConfigService.get<number>({
226→			key: NEURAL_SEARCH_CONVERSATION_TTL,
227→			converter: Number,
228→		});
229→
230→		await this.cacheService.set({
231→			namespace: Namespaces.NEURAL_SEARCH_CONVERSATION,
232→			key: state.conversationId,
233→			value: state,
234→			ttl,
235→		});
236→	}
